# Plan: Add `Bun.INI` Namespace

## Context

Bun already exposes format-specific namespaces on the global `Bun` object:
`Bun.TOML`, `Bun.JSONC`, `Bun.JSON5`, `Bun.YAML`. Each lives in its own
`*Object.zig` file under `src/bun.js/api/`, is wired into the lazy-property
table via `BunObject.zig`, declared in `BunObject+exports.h`, and registered in
the `bunObjectTable` in `BunObject.cpp`.

Bun also contains a battle-tested INI parser at `src/ini.zig` used internally
by the package manager for npm config files. It is exposed via
`bun:internal-for-testing` but has never been made into a public API.

The goal is to add `Bun.INI` with `parse()` and `stringify()`, following the
exact pattern of the existing format namespaces.

---

## Critical Files

| File | Role |
|---|---|
| `src/bun.js/api/INIObject.zig` | **NEW** — the public namespace implementation |
| `src/bun.js/api/BunObject.zig` | Wire INI lazy-property; add getter; add import |
| `src/bun.js/bindings/BunObject+exports.h` | Add `macro(INI)` to `FOR_EACH_GETTER` |
| `src/bun.js/bindings/BunObject.cpp` | Add INI row in `@begin bunObjectTable` |
| `packages/bun-types/bun.d.ts` | Add `namespace INI` TypeScript types |

Reference files to understand patterns:
- `src/bun.js/api/TOMLObject.zig` — simplest parse-only example
- `src/bun.js/api/JSON5Object.zig` — parse + stringify example
- `src/ini.zig` — internal INI parser (the existing `Parser.parse` function)

---

## Step-by-Step Implementation

### Step 1 — Create `src/bun.js/api/INIObject.zig`

Model after `JSON5Object.zig` (parse + stringify). The `parse` function reuses
the existing `src/ini.zig` `Parser`; the `stringify` function is self-contained.

**`create` function:**
```zig
pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(globalThis, ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}));
    object.put(globalThis, ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}));
    return object;
}
```

**`parse` function** — delegates to `src/ini.zig`'s `Parser`:

The internal `IniTestingAPIs.parse` in `src/ini.zig` (line 674) shows exactly
how to call `Parser`. Replicate that logic:

```zig
pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const argument = callframe.argument(0);
    if (argument.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }
    const bunstr = try argument.toBunString(globalThis);
    defer bunstr.deref();
    const utf8str = bunstr.toUTF8(bun.default_allocator);
    defer utf8str.deinit();

    var parser = IniParser.init(
        bun.default_allocator,
        "<input>",
        utf8str.slice(),
        null,  // no env loader for public API
    );
    defer parser.deinit();

    parser.parse(parser.arena.allocator()) catch |err| {
        return globalThis.throwError(err, "Failed to parse INI");
    };

    return parser.out.toJS(bun.default_allocator, globalThis) catch |err| {
        return globalThis.throwError(err, "Failed to convert INI to JS");
    };
}
```

> Note: `IniParser` = `@import("bun").ini.Parser` (see imports section below).
> Check the exact module path — `src/ini.zig` is reachable as `bun.ini` or
> via `@import("root").ini` — verify against how other internal modules are
> imported (e.g., `bun.interchange.toml.TOML`).

**`stringify` function** — self-contained INI serializer:

Iterate JS object properties. Top-level scalars first, then sections (nested
objects).

```zig
pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const argument = callframe.argument(0);
    if (argument.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }
    if (!argument.isObject()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    var sections_builder: wtf.StringBuilder = .init();
    defer sections_builder.deinit();

    var iter: jsc.JSPropertyIterator(.{
        .skip_empty_name = false,
        .include_value = true,
    }) = try .init(globalThis, try argument.toObject(globalThis));
    defer iter.deinit();

    // Two-pass: top-level scalars first, then section objects
    while (try iter.next()) |key| {
        const val = iter.value;
        if (val.isObject() and !val.isArray()) {
            // Write as [section] into sections_builder
            try appendSection(&sections_builder, globalThis, key, val);
        } else {
            // Write as key = value at top level
            try appendKeyValue(&builder, globalThis, key, val);
        }
    }

    // Combine: scalars, blank line, sections
    if (sections_builder.len > 0) {
        if (builder.len > 0) builder.append(.lchar, '\n');
        builder.append(.string, sections_builder.toString(globalThis)); // adapt as needed
    }

    const result = builder.toString(globalThis);
    return result;
}
```

Helper functions `appendKeyValue` and `appendSection` write INI lines:
- `appendKeyValue`: `key = value\n` (values coerced to string)
- `appendSection`: `[section_name]\nkey = value\n` for each property

**Imports block at bottom of file:**
```zig
const std = @import("std");
const bun = @import("bun");
const IniParser = bun.ini.Parser;  // verify exact path
const jsc = bun.jsc;
const JSValue = jsc.JSValue;
const ZigString = jsc.ZigString;
const wtf = jsc.wtf;
```

---

### Step 2 — Update `src/bun.js/api/BunObject.zig`

Three additions, all alphabetically ordered with their peers:

**a) Add `INIObject` import** (near line 2076, alongside other format objects):
```zig
const INIObject = bun.api.INIObject;
```
Insert between `const HashObject = bun.api.HashObject;` and
`const JSON5Object = bun.api.JSON5Object;`.

**b) Add lazy-property declaration** (near line 66, in the `BunObject` struct):
```zig
pub const INI = toJSLazyPropertyCallback(Bun.getINIObject);
```
Insert between `pub const Glob` and `pub const JSONC` (alphabetical: Glob,
INI, JSONC…). Actually, check: existing order is: `Glob` (line ~56), then
`SHA512`, `SHA512_256`, `JSONC`, `markdown`, `TOML`, `JSON5`, `YAML`. The
alphabetical position for `INI` is between `Glob` and `JSONC`... but the
existing entries are not strictly alphabetical. Follow the same grouping:
place `INI` next to JSONC/TOML/JSON5/YAML for clarity:
```zig
pub const INI  = toJSLazyPropertyCallback(Bun.getINIObject);
pub const JSONC = toJSLazyPropertyCallback(Bun.getJSONCObject);
```

**c) Add export** in `exportAll()` (near line 136):
```zig
@export(&BunObject.INI, .{ .name = lazyPropertyCallbackName("INI") });
```
Place next to the other format exports.

**d) Add getter function** (near line 1273):
```zig
pub fn getINIObject(globalThis: *jsc.JSGlobalObject, _: *jsc.JSObject) jsc.JSValue {
    return INIObject.create(globalThis);
}
```

---

### Step 3 — Update `src/bun.js/bindings/BunObject+exports.h`

Add `macro(INI)` to the `FOR_EACH_GETTER` macro list in alphabetical order
between `macro(Glob)` and `macro(JSON5)`:

```cpp
#define FOR_EACH_GETTER(macro) \
    ...
    macro(Glob) \
    macro(INI) \      ← add here
    macro(JSON5) \
    macro(JSONC) \
    ...
```

(Current file: lines 10-27. `macro(JSON5)` is line 12, `macro(Glob)` is
line 11.)

---

### Step 4 — Update `src/bun.js/bindings/BunObject.cpp`

Add the INI row to `@begin bunObjectTable` (around lines 963-968):

```
INI                                            BunObject_lazyPropCb_wrap_INI                                       DontDelete|PropertyCallback
```

Insert alphabetically. Currently `JSONC` is first of the format entries at
line 963. `INI` sorts before `JSONC`, so insert before line 963:

```
INI                                            BunObject_lazyPropCb_wrap_INI                                       DontDelete|PropertyCallback
JSONC                                          BunObject_lazyPropCb_wrap_JSONC                                     DontDelete|PropertyCallback
```

---

### Step 5 — Update `packages/bun-types/bun.d.ts`

Add `namespace INI` after `namespace JSONC` (line 794) and before `namespace JSONL`.

```typescript
/**
 * INI related APIs
 */
namespace INI {
  /**
   * Parse an INI string into a JavaScript object.
   *
   * Supports sections (`[section]`) as nested objects, key=value pairs
   * with optional whitespace around `=`, and comment lines starting
   * with `;` or `#`.
   *
   * @category Utilities
   *
   * @param input The INI string to parse
   * @returns A JavaScript object
   *
   * @example
   * ```ts
   * import { INI } from "bun";
   *
   * const result = INI.parse(`
   * name = my-app
   * version = 1.0.0
   *
   * [database]
   * host = localhost
   * port = 5432
   * `);
   * // { name: "my-app", version: "1.0.0", database: { host: "localhost", port: "5432" } }
   * ```
   */
  export function parse(input: string): Record<string, any>;

  /**
   * Convert a JavaScript object into an INI-formatted string.
   *
   * Top-level scalar values are written as `key = value`. Nested objects
   * are written as `[section]` headers followed by their key-value pairs.
   *
   * @category Utilities
   *
   * @param input The JavaScript object to stringify
   * @returns An INI-formatted string
   *
   * @example
   * ```ts
   * import { INI } from "bun";
   *
   * console.log(INI.stringify({
   *   name: "my-app",
   *   database: { host: "localhost", port: 5432 },
   * }));
   * // name = my-app
   * //
   * // [database]
   * // host = localhost
   * // port = 5432
   * ```
   */
  export function stringify(input: Record<string, any>): string;
