pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const argument = callframe.argument(0);
    if (argument.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    const bunstr = try argument.toBunString(globalThis);
    defer bunstr.deref();
    const utf8str = bunstr.toUTF8(bun.default_allocator);
    defer utf8str.deinit();

    var parser = IniParser.init(
        bun.default_allocator,
        "<input>",
        utf8str.slice(),
        globalThis.bunVM().transpiler.env,
    );
    defer parser.deinit();

    try parser.parse(parser.arena.allocator());

    return parser.out.toJS(bun.default_allocator, globalThis) catch |e| {
        return globalThis.throwError(e, "failed to convert INI to JavaScript");
    };
}

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const argument = callframe.argument(0);
    if (argument.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }
    if (!argument.isObject()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    const obj = try argument.toObject(globalThis);

    // First pass: write top-level scalar key=value pairs
    {
        var iter: jsc.JSPropertyIterator(.{
            .skip_empty_name = false,
            .include_value = true,
        }) = try .init(globalThis, obj);
        defer iter.deinit();

        while (try iter.next()) |key| {
            const val = iter.value;
            // Skip plain objects — they become [section] headers in the second pass
            if (val.isObject() and !val.isArray()) continue;
            if (val.isUndefined() or val.isNull() or val.isSymbol() or val.isFunction()) continue;
            const val_str = try val.toBunString(globalThis);
            defer val_str.deref();
            builder.append(.string, key);
            builder.append(.latin1, " = ");
            builder.append(.string, val_str);
            builder.append(.lchar, '\n');
        }
    }

    // Second pass: write [section] blocks for nested plain objects
    {
        var iter: jsc.JSPropertyIterator(.{
            .skip_empty_name = false,
            .include_value = true,
        }) = try .init(globalThis, obj);
        defer iter.deinit();

        while (try iter.next()) |key| {
            const val = iter.value;
            if (!val.isObject() or val.isArray()) continue;

            builder.append(.lchar, '\n');
            builder.append(.lchar, '[');
            builder.append(.string, key);
            builder.append(.latin1, "]\n");

            const section_obj = try val.toObject(globalThis);
            var section_iter: jsc.JSPropertyIterator(.{
                .skip_empty_name = false,
                .include_value = true,
            }) = try .init(globalThis, section_obj);
            defer section_iter.deinit();

            while (try section_iter.next()) |section_key| {
                const section_val = section_iter.value;
                if (section_val.isObject() or section_val.isUndefined() or section_val.isNull() or section_val.isSymbol() or section_val.isFunction()) continue;
                const val_str = try section_val.toBunString(globalThis);
                defer val_str.deref();
                builder.append(.string, section_key);
                builder.append(.latin1, " = ");
                builder.append(.string, val_str);
                builder.append(.lchar, '\n');
            }
        }
    }

    return builder.toString(globalThis);
}

